function formatTime12Hour(e){const t=new Date(e);let r=t.getHours();const n=t.getMinutes(),i=r>=12?"PM":"AM";r%=12,r=r||12;return`${r}:${n<10?"0"+n:n} ${i}`}function formatTimeWithTimezone(e,t){return`${formatTime12Hour(e)} ${getTimezoneAbbreviation(t)}`}function getTimezoneAbbreviation(e){return{"Asia/Manila":"PHT","Asia/Tokyo":"JST","Asia/Bangkok":"ICT","Europe/Amsterdam":"CET","Europe/Zurich":"CET","Europe/Rome":"CET"}[e]||e.split("/")[1].substring(0,3).toUpperCase()}function formatDuration(e){const t=Math.floor(e/60),r=e%60;return 0===t?`${r}m`:0===r?`${t}h`:`${t}h ${r}m`}function calculateArrivalTime(e,t){const r=new Date(e);return new Date(r.getTime()+6e4*t)}function formatArrivalTime(e,t,r){return formatTimeWithTimezone(calculateArrivalTime(e,t).toISOString(),r)}function formatDate(e){return`${["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"][e.getMonth()]} ${e.getDate()}`}function getTimezoneDifference(e,t,r,n){const i={"Asia/Manila":8,"Asia/Tokyo":9,"Asia/Bangkok":7,"Europe/Amsterdam":1,"Europe/Zurich":1,"Europe/Rome":1};return(i[n]||0)-(i[r]||0)}function debounce(e,t){let r;return function(...n){clearTimeout(r),r=setTimeout(()=>e.apply(this,n),t)}}function isNextDayArrival(e,t){const r=new Date(e),n=calculateArrivalTime(e,t);return r.getDate()!==n.getDate()||r.getMonth()!==n.getMonth()||r.getFullYear()!==n.getFullYear()}function renderTimezoneDifferenceIndicator(e,t,r,n){if(r===n)return"";const i=getTimezoneDifference(e,t,r,n);return`<span class="timezone-diff" title="Timezone difference">${`${i>0?"+":""}${i}h`}</span>`}function renderNextDayIndicator(e,t){if(!isNextDayArrival(e,t))return"";return`<span class="next-day-indicator" title="Arrives next day">(${formatDate(calculateArrivalTime(e,t))})</span>`}function initializeLazyLoading(){if(!("IntersectionObserver"in window)){return void document.querySelectorAll("img[data-src]").forEach(e=>{e.src=e.dataset.src,e.classList.add("loaded")})}const e=new IntersectionObserver((e,t)=>{e.forEach(e=>{if(e.isIntersecting){const r=e.target;r.src=r.dataset.src,r.addEventListener("load",()=>{r.classList.add("loaded")}),r.addEventListener("error",()=>{r.src="img/default.jpg",r.classList.add("loaded")}),t.unobserve(r)}})},{rootMargin:"50px",threshold:.01});document.querySelectorAll("img[data-src]").forEach(t=>{e.observe(t)})}function reinitializeLazyLoading(){initializeLazyLoading()}